interface.signature:
interface StepHandler {
  executeStep(step: WorkflowStep, context: ExecutionContext, userInput?: any): Promise<StepResult>;
}

interface StepResult {
  output: any;
  nextStepNumber: number | null;
  requiresUserInput: boolean;
}

interface ExecutionContext {
  systemVariables: { current_user_id: string, execution_id: string, date: string };
  executionVariables: Record<string, any>; // from workflow_executions.variables
  stepOutputs: Record<number, any>; // from executedSteps
  defaultValues: Record<string, any>; // from step config
}

export const workflowRouter = router({
  execute: publicProcedure.input(z.object({ workflowId: z.string(), projectId: z.string().optional() })).mutation(async ({ input }) => { ... }),
  submitStep: publicProcedure.input(z.object({ executionId: z.string(), stepNumber: z.number(), userInput: z.any() })).mutation(async ({ input }) => { ... }),
  getExecution: publicProcedure.input(z.object({ executionId: z.string() })).query(async ({ input }) => { ... }),
  onWorkflowEvent: publicProcedure.input(z.object({ executionId: z.string() })).subscription(({ input }) => { ... })
});

interface WorkflowStepperWizardProps {
  currentStep: number;
  totalSteps: number;
  steps: WorkflowStepDefinition[];
  onStepClick?: (stepNumber: number) => void;
}

export function WorkflowStepperWizard({ currentStep, totalSteps, steps, onStepClick }: WorkflowStepperWizardProps) { ... }
